/**
 * Test Types Module
 * 
 * Shared TypeScript types and interfaces for test utilities.
 * Layer: Types (Layer 1)
 * 
 * This module provides type definitions used across the test infrastructure
 * to ensure type safety and consistency in test implementations.
 */

import { Logger } from '../logging/logger';

// ============================================================================
// Core Test Types
// ============================================================================

/**
 * Represents the possible states of a test execution
 */
export enum TestStatus {
  PENDING = 'pending',
  RUNNING = 'running',
  PASSED = 'passed',
  FAILED = 'failed',
  SKIPPED = 'skipped',
  TIMEOUT = 'timeout',
}

/**
 * Severity levels for test failures
 */
export enum TestSeverity {
  CRITICAL = 'critical',
  HIGH = 'high',
  MEDIUM = 'medium',
  LOW = 'low',
  INFO = 'info',
}

// ============================================================================
// Test Configuration Types
// ============================================================================

/**
 * Configuration options for test execution
 * Layer: Config (Layer 2)
 */
export interface TestConfig {
  /** Unique identifier for the test configuration */
  readonly id: string;

  /** Human-readable name of the test suite */
  readonly name: string;

  /** Timeout in milliseconds for test execution */
  readonly timeoutMs: number;

  /** Whether to run tests in parallel */
  readonly parallel: boolean;

  /** Number of retry attempts for flaky tests */
  readonly retries: number;

  /** Environment variables for test execution */
  readonly env: Record<string, string>;

  /** Tags for categorizing and filtering tests */
  readonly tags: readonly string[];
}

/**
 * Default test configuration values
 */
export const DEFAULT_TEST_CONFIG: Readonly<Required<Omit<TestConfig, 'id' | 'name'>>> = {
  timeoutMs: 30000,
  parallel: false,
  retries: 0,
  env: {},
  tags: [],
} as const;

// ============================================================================
// Test Repository Types
// ============================================================================

/**
 * Represents a test case definition
 * Layer: Repo (Layer 3)
 */
export interface TestCase<TInput = unknown, TExpected = unknown> {
  /** Unique identifier for the test case */
  readonly id: string;

  /** Descriptive name of the test case */
  readonly description: string;

  /** Input data for the test */
  readonly input: TInput;

  /** Expected output or result */
  readonly expected: TExpected;

  /** Optional setup function to run before test */
  readonly setup?: () => Promise<void> | void;

  /** Optional teardown function to run after test */
  readonly teardown?: () => Promise<void> | void;

  /** Tags for categorization */
  readonly tags: readonly string[];
}

/**
 * Repository of test cases for a specific feature or module
 */
export interface TestRepository<TInput = unknown, TExpected = unknown> {
  /** Repository identifier */
  readonly id: string;

  /** Collection of test cases */
  readonly cases: ReadonlyArray<TestCase<TInput, TExpected>>;

  /** Get test cases filtered by tags */
  getByTags(tags: readonly string[]): ReadonlyArray<TestCase<TInput, TExpected>>;

  /** Get a specific test case by ID */
  getById(id: string): TestCase<TInput, TExpected> | undefined;
}

// ============================================================================
// Test Service Types
// ============================================================================

/**
 * Result of a single test execution
 * Layer: Service (Layer 4)
 */
export interface TestResult {
  /** Test case identifier */
  readonly testId: string;

  /** Final status of the test */
  readonly status: TestStatus;

  /** Execution duration in milliseconds */
  readonly durationMs: number;

  /** Timestamp when test completed */
  readonly completedAt: Date;

  /** Error information if test failed */
  readonly error?: TestError;

  /** Additional metadata from test execution */
  readonly metadata: Record<string, unknown>;
}

/**
 * Structured error information for test failures
 */
export interface TestError {
  /** Error message */
  readonly message: string;

  /** Error severity level */
  readonly severity: TestSeverity;

  /** Stack trace if available */
  readonly stack?: string;

  /** Additional context about the failure */
  readonly context: Record<string, unknown>;
}

/**
 * Interface for test execution services
 */
export interface TestService {
  /** Execute a single test case */
  execute<TInput, TExpected>(
    testCase: TestCase<TInput, TExpected>,
    config: TestConfig
  ): Promise<TestResult>;

  /** Execute multiple test cases */
  executeBatch(
    testCases: ReadonlyArray<TestCase>,
    config: TestConfig
  ): Promise<ReadonlyArray<TestResult>>;
}

// ============================================================================
// Test Runtime Types
// ============================================================================

/**
 * Runtime context for test execution
 * Layer: Runtime (Layer 5)
 */
export interface TestRuntimeContext {
  /** Unique execution identifier */
  readonly executionId: string;

  /** Logger instance for structured logging */
  readonly logger: Logger;

  /** Start time of the test run */
  readonly startedAt: Date;

  /** Shared state across test execution */
  readonly state: Map<string, unknown>;

  /** Abort controller for cancellation */
  readonly abortController: AbortController;
}

/**
 * Options for creating a test runtime context
 */
export interface TestRuntimeOptions {
  /** Optional execution ID (generated if not provided) */
  readonly executionId?: string;

  /** Custom logger instance */
  readonly logger?: Logger;

  /** Initial state values */
  readonly initialState?: Record<string, unknown>;
}

/**
 * Interface for test runtime implementations
 */
export interface TestRuntime {
  /** Initialize the runtime environment */
  initialize(options: TestRuntimeOptions): Promise<TestRuntimeContext>;

  /** Clean up resources after test execution */
  teardown(context: TestRuntimeContext): Promise<void>;

  /** Check if runtime is healthy */
  healthCheck(): Promise<boolean>;
}

// ============================================================================
// Test UI Types
// ============================================================================

/**
 * Represents a test report for display
 * Layer: UI (Layer 6)
 */
export interface TestReport {
  /** Report identifier */
  readonly id: string;

  /** Summary statistics */
  readonly summary: TestSummary;

  /** Detailed results for each test */
  readonly results: ReadonlyArray<TestResult>;

  /** Formatted duration string */
  readonly duration: string;

  /** Generated timestamp */
  readonly generatedAt: Date;
}

/**
 * Summary statistics for test execution
 */
export interface TestSummary {
  /** Total number of tests */
  readonly total: number;

  /** Number of passed tests */
  readonly passed: number;

  /** Number of failed tests */
  readonly failed: number;

  /** Number of skipped tests */
  readonly skipped: number;

  /** Overall success rate (0-1) */
  readonly successRate: number;

  /** Total execution time in milliseconds */
  readonly totalDurationMs: number;
}

/**
 * Formatter for test reports
 */
export interface TestReportFormatter {
  /** Format test results as a report */
  format(results: ReadonlyArray<TestResult>): TestReport;

  /** Serialize report to string format */
  serialize(report: TestReport): string;
}

// ============================================================================
// Utility Types
// ============================================================================

/**
 * Type guard to check if a value is a valid TestStatus
 */
export function isTestStatus(value: unknown): value is TestStatus {
  return Object.values(TestStatus).includes(value as TestStatus);
}

/**
 * Type guard to check if a value is a valid TestError
 */
export function isTestError(value: unknown): value is TestError {
  if (typeof value !== 'object' || value === null) {
    return false;
  }

  const error = value as Record<string, unknown>;

  return (
    typeof error.message === 'string' &&
    Object.values(TestSeverity).includes(error.severity as TestSeverity) &&
    typeof error.context === 'object' &&
    error.context !== null
  );
}

/**
 * Creates a standardized TestError from an unknown error value
 */
export function createTestError(
  error: unknown,
  severity: TestSeverity = TestSeverity.HIGH,
  context: Record<string, unknown> = {}
): TestError {
  if (isTestError(error)) {
    return error;
  }

  const message = error instanceof Error ? error.message : String(error);
  const stack = error instanceof Error ? error.stack : undefined;

  return {
    message,
    severity,
    stack,
    context: {
      ...context,
      originalError: error,
    },
  };
}

/**
 * Validates a TestConfig object
 * @throws Error if configuration is invalid
 */
export function validateTestConfig(config: unknown): asserts config is TestConfig {
  if (typeof config !== 'object' || config === null) {
    throw new Error('TestConfig must be an object');
  }

  const c = config as Record<string, unknown>;

  if (typeof c.id !== 'string' || c.id.length === 0) {
    throw new Error('TestConfig.id must be a non-empty string');
  }

  if (typeof c.name !== 'string' || c.name.length === 0) {
    throw new Error('TestConfig.name must be a non-empty string');
  }

  if (typeof c.timeoutMs !== 'number' || c.timeoutMs <= 0) {
    throw new Error('TestConfig.timeoutMs must be a positive number');
  }

  if (typeof c.parallel !== 'boolean') {
    throw new Error('TestConfig.parallel must be a boolean');
  }

  if (typeof c.retries !== 'number' || c.retries < 0) {
    throw new Error('TestConfig.retries must be a non-negative number');
  }

  if (typeof c.env !== 'object' || c.env === null) {
    throw new Error('TestConfig.env must be an object');
  }

  if (!Array.isArray(c.tags)) {
    throw new Error('TestConfig.tags must be an array');
  }
}
